import bz2
import csv
from collections import defaultdict

sde_dir = './sde'

# Check industryActivityProducts
products = defaultdict(list)
filepath = sde_dir + '/industryActivityProducts.csv.bz2'
with bz2.open(filepath, 'rt', encoding='utf-8') as f:
    reader = csv.DictReader(f)
    for row in reader:
        key = (int(row['typeID']), int(row['activityID']))
        products[key].append({
            'productTypeID': int(row['productTypeID']),
            'quantity': int(row['quantity'])
        })

# Check invBlueprints
blueprints = defaultdict(list)
filepath = sde_dir + '/industryBlueprints.csv.bz2'
with bz2.open(filepath, 'rt', encoding='utf-8') as f:
    reader = csv.DictReader(f)
    for row in reader:
        blueprints[int(row['blueprintTypeID'])].append({
            'productTypeID': int(row['productTypeID']),
        })

# Check for Barrage L Blueprint (12776)
print('Manufacturing products of Barrage L Blueprint (12776):')
for key, val in products.items():
    if key[0] == 12776:
        print(f'  Key: {key}, Products: {val}')

print('\\nBlueprints for product 12775 (Barrage L):')
for bp_id, prods in blueprints.items():
    for p in prods:
        if p['productTypeID'] == 12775:
            print(f'  Blueprint ID: {bp_id}')
            for k, v in products.items():
                if k[0] == bp_id:
                    print(f'    Manufacturing products: {v}')
